INSERT INTO products (id,handle,title,description,description_html,product_type,tags_json,images_json,price_min_cents,price_max_cents,currency) VALUES ('gid://shopify/Product/9242163413157','gift-tags','Letterpress Gift Tags with Satin Ribbon','Elevate every present with Longbourn Letterpress Gift Tags. Each motif is pressed into thick, archival cotton stock and finished by hand with satin ribbon, bringing a tailored, heirloom touch to your wrapping. Choose your occasion, then select a design—each tag ready for a personal note. Letterpress printed on heavyweight cotton stock Hand-tied satin ribbon included Assorted motifs and greetings Made in the U.S.A.','<p>Elevate every present with Longbourn Letterpress Gift Tags. Each motif is pressed into thick, archival cotton stock and finished by hand with satin ribbon, bringing a tailored, heirloom touch to your wrapping. Choose your occasion, then select a design—each tag ready for a personal note.</p><ul>
