INSERT INTO products (id,handle,title,description,description_html,product_type,tags_json,images_json,price_min_cents,price_max_cents,currency) VALUES ('gid://shopify/Product/9241857458341','grand-tags','Letterpress Grand Tags with Satin Ribbon','Our Grand Tags are generous, frame-worthy tags for gifts that deserve a flourish. Each design is letterpress printed on thick, archival stock with a refined texture and finished with hand-tied ribbon. Select your motif to match the moment—botanical wreaths, heraldic crests, or whimsical illustrations—then personalize with your message. These tags turn any present into a keepsake. Heavyweight cotton stock Letterpress impression Hand-tied ribbon Assorted motifs','<p>Our Grand Tags are generous, frame-worthy tags for gifts that deserve a flourish. Each design is letterpress printed on thick, archival stock with a refined texture and finished with hand-tied ribbon. Select your motif to match the moment—botanical wreaths, heraldic crests, or whimsical illustrations—then personalize with your message. These tags turn any present into a keepsake.</p><ul>
