INSERT INTO products (id,handle,title,description,description_html,product_type,tags_json,images_json,price_min_cents,price_max_cents,currency) VALUES ('gid://shopify/Product/9242070810789','longbourn-stationery','Letterpress Note Card & Envelope Set','A note penned on fine stationery is a quiet act of grace. Each Longbourn design offers its own charm — from delicate pastels and tailored nautical trims to playful hearts and ornate ribbons. Printed on thick, smooth paper that welcomes fountain pen ink or a favorite ballpoint, these cards elevate correspondence into an art form.Perfect for thank‑you notes, invitations, or a thoughtful hello. Choose a design for every sentiment and season. Flat card with coordinating envelope Luxe, heavyweight paper Dimensions: 2.5 x 3 inches Designed and printed in the U.S.A.','<p>A note penned on fine stationery is a quiet act of grace. Each Longbourn design offers its own charm — from delicate pastels and tailored nautical trims to playful hearts and ornate ribbons. Printed on thick, smooth paper that welcomes fountain pen ink or a favorite ballpoint, these cards elevate correspondence into an art form.</p><p>Perfect for thank‑you notes, invitations, or a thoughtful hello. Choose a design for every sentiment and season.</p><ul>
