INSERT INTO products (id,handle,title,description,description_html,product_type,tags_json,images_json,price_min_cents,price_max_cents,currency) VALUES ('gid://shopify/Product/9243225620645','petite-cards-singles-six-packs','Petite Letterpress Note Cards','Some gestures are better whispered than shouted. A handwritten note slipped into a book, tucked under a cup, or left by a door says what emails never could — I thought of you, and it mattered enough to pause. Each Petite Card was designed for that moment. Printed on soft, cotton paper that remembers the press of the letterform, they carry a quiet confidence — elegant but unpretentious, beautiful without trying too hard. They are the sort of cards that live in desk drawers beside good pens and secrets, ready for the next thank-you, congratulations, or confession. Keep a six-pack and never be caught without a proper note again — or choose a single to accompany a gift, a gesture, or something that deserves its own envelope. Longbourn Papers. For the beautiful act of slowing down. Proudly Made in the USA.','<p class="p1">Some gestures are better whispered than shouted. A handwritten note slipped into a book, tucked under a cup, or left by a door says what emails never could — <i>I thought of you, and it mattered enough to pause.</i><i></i></p>
